@Singleton
class ProductController @Inject()(db: Database) extends Controller {

  def searchProducts() = Action.async { implicit request =>
    val queryParams = request.queryString

    val whereClauses = queryParams.flatMap {
      case ("name", value) => Some(s"name LIKE '%$1%'")
